import os
from http import HTTPStatus as status
import flask
from flask import jsonify, request


# pylint: disable = C0302
app = flask.Flask(__name__)
auths = {}
secrets = {
    'secret': '<KEY>',
}


@app.route('/')
def index():
    return '''
        <h1>Hello!</h1>
        ''' + (
        '''
        <a href="/authorize?client_id=9999&redirect_uri=https://www.example.com">
            Click to Authorize
        </a>''' if 'client' not in request.args else '')


@app.route('/login')
def login():
    return jsonify(
        error=1,
        status='Invalid client credentials',
    ) \
           if (not all([
               'client_id' in request.args,
               'client_secret' in secrets and secrets['client_secret'] == request.args['client_secret'],
           ])) else jsonify(**{
                'access_token': '{}'.format(os.urandom(20).hex()),  # randomly generated. 32 bytes.
                'token_type': 'bearer',
            })


@app.route('/authorize')
def authorize():
    return jsonify({
        "code": "{}".format('1234'.encode().hex())[:5],

        # The request will also be POST'ed to the redirect URI specified by client_id.
        'access_token': '{}'.format(os.urandom(20).hex()),  # randomly generated. 32 bytes.
        'token_type': 'bearer',
    })


@app.route('/token')
def token():
    code = request.args['code']

    return jsonify({

        # This is the user id of the requesting user
        "user": auths[code] if all([
            'code' in request.args,
            len(request.args["code"]) >= 5 and request.args['client_id'],
            'client_secret' in secrets and secrets['client_secret'] == request.args['client_secret'],
        ]) else None
    })


if __name__ == "__main__":
    app.run()